import{_ as e,o,c as r,ag as t}from"./chunks/framework.DjqkqlVQ.js";const u=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"mods/sts2-god-mod/faq.md","filePath":"mods/sts2-god-mod/faq.md","lastUpdated":1778341931000}'),d={name:"mods/sts2-god-mod/faq.md"};function h(i,a,l,n,s,c){return o(),r("div",null,[...a[0]||(a[0]=[t('<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><h2 id="god-mod-是做什么的" tabindex="-1">God Mod 是做什么的？ <a class="header-anchor" href="#god-mod-是做什么的" aria-label="Permalink to &quot;God Mod 是做什么的？&quot;">​</a></h2><p>God Mod 是 杀戮尖塔2 的工具型 / 作弊型 Mod，用于测试、沙盒玩法、构筑实验和快速起局。它让你可以直接修改资源、卡牌、遗物、药水、战斗状态和部分流程。</p><h2 id="它适合正常流程游玩吗" tabindex="-1">它适合正常流程游玩吗？ <a class="header-anchor" href="#它适合正常流程游玩吗" aria-label="Permalink to &quot;它适合正常流程游玩吗？&quot;">​</a></h2><p>不太适合。它会主动修改游戏状态，更适合测试、实验、复现问题或构筑验证。</p><h2 id="怎么打开面板" tabindex="-1">怎么打开面板？ <a class="header-anchor" href="#怎么打开面板" aria-label="Permalink to &quot;怎么打开面板？&quot;">​</a></h2><p>可以点击游戏内悬浮 <code>G</code> 按钮，或长按 <code>G</code> 快捷键打开。</p><h2 id="可以编辑哪些资源" tabindex="-1">可以编辑哪些资源？ <a class="header-anchor" href="#可以编辑哪些资源" aria-label="Permalink to &quot;可以编辑哪些资源？&quot;">​</a></h2><p>可以编辑金币、当前生命值、最大生命值、能量和药水槽，也可以添加、补满或清空药水。</p><h2 id="卡牌能改到什么程度" tabindex="-1">卡牌能改到什么程度？ <a class="header-anchor" href="#卡牌能改到什么程度" aria-label="Permalink to &quot;卡牌能改到什么程度？&quot;">​</a></h2><p>支持添加、删除、复制、变化、升级、降级、附魔、关键词编辑和数值编辑。也支持保存和应用自定义卡组预设。</p><h2 id="支持遗物管理吗" tabindex="-1">支持遗物管理吗？ <a class="header-anchor" href="#支持遗物管理吗" aria-label="Permalink to &quot;支持遗物管理吗？&quot;">​</a></h2><p>支持。可以添加或删除遗物，也支持快捷遗物组合，适合快速搭建测试环境。</p><h2 id="战斗中能做什么" tabindex="-1">战斗中能做什么？ <a class="header-anchor" href="#战斗中能做什么" aria-label="Permalink to &quot;战斗中能做什么？&quot;">​</a></h2><p>可以添加或移除状态，满血、满能量、清除减益、击杀全部敌人，并进行抽牌 / 弃牌控制。也支持在战斗中生成敌人。</p><h2 id="能直接测试事件吗" tabindex="-1">能直接测试事件吗？ <a class="header-anchor" href="#能直接测试事件吗" aria-label="Permalink to &quot;能直接测试事件吗？&quot;">​</a></h2><p>可以在跑图过程中直接进入指定事件，用来验证事件分支、奖励或兼容性问题。</p><h2 id="多人模式安全吗" tabindex="-1">多人模式安全吗？ <a class="header-anchor" href="#多人模式安全吗" aria-label="Permalink to &quot;多人模式安全吗？&quot;">​</a></h2><p>God Mod 会修改大量游戏状态。单人测试和沙盒使用是最推荐的场景；如果在多人环境中使用，建议只在所有玩家都明确同意的测试局中开启。</p><h2 id="未来会支持更多语言吗" tabindex="-1">未来会支持更多语言吗？ <a class="header-anchor" href="#未来会支持更多语言吗" aria-label="Permalink to &quot;未来会支持更多语言吗？&quot;">​</a></h2><p>计划中。当前已有英文和简体中文基础，后续路线图包含繁体中文、日语、韩语、俄语、西班牙语和巴西葡萄牙语等方向。</p><h2 id="后续最重要的功能方向是什么" tabindex="-1">后续最重要的功能方向是什么？ <a class="header-anchor" href="#后续最重要的功能方向是什么" aria-label="Permalink to &quot;后续最重要的功能方向是什么？&quot;">​</a></h2><p>当前优先方向包括多语言扩展、可调手牌上限、Traveler 模式体验改进、面板内引导、预设系统增强和可分享开局预设包。</p><h2 id="可以转载或打包进整合包吗" tabindex="-1">可以转载或打包进整合包吗？ <a class="header-anchor" href="#可以转载或打包进整合包吗" aria-label="Permalink to &quot;可以转载或打包进整合包吗？&quot;">​</a></h2><p>未经许可，请勿转载、重新上传、打包进付费整合包，或分发修改后的版本。</p>',25)])])}const m=e(d,[["render",h]]);export{u as __pageData,m as default};
